mapper.select:
SELECT
FROM tb_stl_settlement_mng a LEFT OUTER JOIN tb_mbm_admin_user b ON a.create_id = b.id LEFT OUTER JOIN tb_mbm_admin_user c ON a.modified_id = c.id WHERE 1=1
ORDER BY a.id DESC LIMIT #{offset}, #{recordSize}

mapper.delete:
DELETE FROM tb_stl_settlement_mng
WHERE yyyymm = #{stlTYyyymm} 
AND company_id = #{companyId}
